argv:
flags=""
case "$MODE" in
  preview) flags="--preview" ;;
  full) flags="-full" ;;
esac
[ "$PR" = "true" ] && flags="$flags -pr"
case "$PAR" in
  sequential) flags="$flags -seq" ;;
  dc_parallel) flags="$flags -dcpar" ;;
esac
set -- "$KS"
[ -n "$TBL" ] && set -- "$@" "$TBL"
exec nodetool repair $flags "$@"
